import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";

// Simulate admin role (replace with real logic if needed)
const isAdmin = true;

const AdvisoryForm = () => {
  const [user, setUser] = useState("");
  const [advisory, setAdvisory] = useState("");
  const [advisories, setAdvisories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [editId, setEditId] = useState(null);
  const listRef = useRef(null);

  useEffect(() => {
    fetchAdvisories();
  }, []);

  const fetchAdvisories = async () => {
    setLoading(true);
    try {
      const response = await axios.get("http://localhost:5000/api/advisory/getAll");
      // Sort by newest first
      const sorted = response.data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
      setAdvisories(sorted);
    } catch (err) {
      setError("Failed to fetch advisories.");
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async () => {
    if (!user || !advisory) {
      setError("Please enter both name and advisory.");
      return;
    }
    setLoading(true);
    setError("");

    try {
      if (editId) {
        await axios.put(`http://localhost:5000/api/advisory/update/${editId}`, {
          user,
          advisory
        });
        setEditId(null);
      } else {
        await axios.post("http://localhost:5000/api/advisory/add", { user, advisory });
      }

      await fetchAdvisories();
      setUser("");
      setAdvisory("");
    } catch (err) {
      setError("Failed to submit advisory.");
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (adv) => {
    setUser(adv.user);
    setAdvisory(adv.advisory);
    setEditId(adv._id);
  };

  const handleDelete = async (id) => {
    try {
      await axios.delete(`http://localhost:5000/api/advisory/delete/${id}`);
      await fetchAdvisories();
    } catch (err) {
      setError("Failed to delete advisory.");
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.5 }}
      style={{ backgroundColor: "#F5DEB3", minHeight: "100vh", padding: "20px" }}
    >
      <div style={{ maxWidth: "900px", margin: "auto", padding: "15px" }}>
        <motion.h2 
          initial={{ y: -20 }}
          animate={{ y: 0 }}
          transition={{ duration: 0.5 }}
          style={{ color: "#121111", textAlign: "center" }}
        >
          Advisory Section
        </motion.h2>

        <motion.div 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 0.5, delay: 0.2 }}
          style={{ marginBottom: "20px" }}
        >
          <motion.input
            whileFocus={{ scale: 1.02 }}
            transition={{ duration: 0.2 }}
            type="text"
            placeholder="Your Name"
            value={user}
            onChange={(e) => setUser(e.target.value)}
            style={{
              padding: "12px",
              width: "100%",
              marginBottom: "10px",
              border: "2px solid #8B4513",
              borderRadius: "8px",
            }}
          />
          <motion.textarea
            whileFocus={{ scale: 1.02 }}
            transition={{ duration: 0.2 }}
            placeholder="Write your advisory here..."
            value={advisory}
            onChange={(e) => setAdvisory(e.target.value)}
            style={{
              padding: "12px",
              width: "100%",
              marginBottom: "10px",
              height: "80px",
              border: "2px solid #8B4513",
              borderRadius: "8px",
              resize: "vertical",
            }}
          ></motion.textarea>
          <motion.button
            onClick={handleSubmit}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            style={{
              padding: "12px 25px",
              backgroundColor: "#066b06",
              color: "white",
              border: "none",
              borderRadius: "8px",
              cursor: "pointer",
              fontWeight: "bold",
            }}
          >
            {editId ? "Update" : "Submit"}
          </motion.button>
          {loading && <p>Loading...</p>}
          {error && <p style={{ color: "red" }}>{error}</p>}
        </motion.div>

        <motion.h3 
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.5, delay: 0.3 }}
          style={{ color: "#121111", marginBottom: "10px" }}
        >
          Recent Advisories
        </motion.h3>
        <motion.div
          ref={listRef}
          style={{
            maxHeight: "400px",
            overflowY: "auto",
            scrollBehavior: "smooth",
            padding: "10px 0",
          }}
        >
          {advisories.length === 0 ? (
            <p>No advisories yet.</p>
          ) : (
            <ul style={{ listStyleType: "none", padding: 0 }}>
              <AnimatePresence>
                {advisories.map((adv, index) => (
                  <motion.li
                    key={adv._id}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -20 }}
                    transition={{ duration: 0.4, delay: index * 0.05 }}
                    style={{
                      background: "#FFF8DC",
                      margin: "15px 0",
                      padding: "15px",
                      borderRadius: "8px",
                      border: "2px solid #8B4513",
                      position: "relative",
                    }}
                  >
                    <div style={{ marginBottom: "5px" }}>
                      <strong style={{ color: "#066b06" }}>{adv.user}</strong>: {adv.advisory}
                    </div>
                    <div style={{ fontSize: "12px", color: "#555" }}>
                      {new Date(adv.createdAt).toLocaleString()}
                    </div>

                    {isAdmin && (
                      <div style={{ marginTop: "10px" }}>
                        <button 
                          onClick={() => handleEdit(adv)} 
                          style={{ marginRight: "10px", color: "#fff", background: "#007bff", border: "none", padding: "5px 10px", borderRadius: "5px", cursor: "pointer" }}
                        >
                          Edit
                        </button>
                        <button 
                          onClick={() => handleDelete(adv._id)} 
                          style={{ color: "#fff", background: "#dc3545", border: "none", padding: "5px 10px", borderRadius: "5px", cursor: "pointer" }}
                        >
                          Delete
                        </button>
                      </div>
                    )}
                  </motion.li>
                ))}
              </AnimatePresence>
            </ul>
          )}
        </motion.div>
      </div>
    </motion.div>
  );
};

export default AdvisoryForm;
